export interface CommandCenterItem {
  /** Optional supporting command copy included in search and result presentation. */
  readonly description?: string;
  /** Prevents command activation while preserving result context. */
  readonly disabled?: boolean;
  /** Human-readable group name used to organize search results. */
  readonly group: string;
  /** Stable unique command identifier passed to execution and consumer callbacks. */
  readonly id: string;
  /** Optional hidden search aliases evaluated by the consumer adapter. */
  readonly keywords?: readonly string[];
  /** Required human-readable command name. */
  readonly label: string;
  /** Optional keyboard hint shown only when shortcut presentation is enabled. */
  readonly shortcut?: string;
}

export interface CommandCenterAdapter {
  /** Executes a selected command with lifecycle cancellation. */
  readonly execute: (commandId: string, signal: AbortSignal) => Promise<void> | void;
  /** Optionally loads recent commands for an empty query; omission yields a clean empty state. */
  readonly loadRecent?: (signal: AbortSignal) => Promise<readonly CommandCenterItem[]>;
  /** Searches consumer-owned commands for the normalized query with lifecycle cancellation. */
  readonly search: (query: string, signal: AbortSignal) => Promise<readonly CommandCenterItem[]>;
}

const COMMANDS: readonly CommandCenterItem[] = [
  {
    description: "Open the component inventory and maturity evidence.",
    group: "Navigate",
    id: "open-catalog",
    keywords: ["components", "inventory", "quality"],
    label: "Open component catalog",
    shortcut: "G C",
  },
  {
    description: "Review deterministic generation and parity records.",
    group: "Navigate",
    id: "open-generation-evidence",
    keywords: ["registry", "generation", "parity"],
    label: "Open generation evidence",
    shortcut: "G E",
  },
  {
    description: "Create a local review note without a network request.",
    group: "Actions",
    id: "create-review-note",
    keywords: ["note", "review", "local"],
    label: "Create review note",
    shortcut: "N",
  },
  {
    description: "Refresh the consumer-owned search index.",
    group: "Actions",
    id: "refresh-search-index",
    keywords: ["reload", "index"],
    label: "Refresh search index",
  },
];

export function createDeterministicCommandCenterAdapter(): CommandCenterAdapter {
  return {
    async execute(_commandId, signal) {
      if (signal.aborted) throw new DOMException("The operation was aborted.", "AbortError");
    },
    async loadRecent(signal) {
      if (signal.aborted) throw new DOMException("The operation was aborted.", "AbortError");
      return COMMANDS.slice(0, 2).map((command) => ({ ...command, group: "Recent" }));
    },
    async search(query, signal) {
      if (signal.aborted) throw new DOMException("The operation was aborted.", "AbortError");
      const terms = query.trim().toLocaleLowerCase().split(/\s+/u).filter(Boolean);
      return COMMANDS.filter((command) => {
        const text = [
          command.label,
          command.description,
          command.group,
          ...(command.keywords ?? []),
        ]
          .filter((value): value is string => value !== undefined)
          .join(" ")
          .toLocaleLowerCase();
        return terms.every((term) => text.includes(term));
      });
    },
  };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

import type { CommandCenterAdapter, CommandCenterItem } from "./command-center-adapter";

export type CommandCenterSearchState = "empty" | "error" | "idle" | "loading" | "ready";

export interface UseCommandCenterOptions {
  /** Consumer adapter that owns command discovery and execution. */
  readonly adapter: CommandCenterAdapter;
  /** Non-negative delay in milliseconds before adapter search begins. */
  readonly debounceMs?: number;
  /** Initial query for uncontrolled search. */
  readonly defaultQuery?: string;
  /** Non-negative character threshold below which search remains idle. */
  readonly minimumQueryLength?: number;
  /** Reports controlled or uncontrolled query changes. */
  readonly onQueryChange?: (query: string) => void;
  /** Controlled search query; use with `onQueryChange`. */
  readonly query?: string;
  /** Loads recent commands for an empty query when the adapter supports them. */
  readonly recentCommands?: boolean;
}

export function useCommandCenter({
  adapter,
  debounceMs = 120,
  defaultQuery = "",
  minimumQueryLength = 1,
  onQueryChange,
  query,
  recentCommands = false,
}: UseCommandCenterOptions) {
  if (!Number.isFinite(debounceMs) || debounceMs < 0) {
    throw new RangeError("Mergora CommandCenter debounceMs must be a finite non-negative number.");
  }
  if (!Number.isInteger(minimumQueryLength) || minimumQueryLength < 0) {
    throw new RangeError(
      "Mergora CommandCenter minimumQueryLength must be a non-negative integer.",
    );
  }
  const [uncontrolledQuery, setUncontrolledQuery] = useState(defaultQuery);
  const [commands, setCommands] = useState<readonly CommandCenterItem[]>([]);
  const [state, setState] = useState<CommandCenterSearchState>("idle");
  const [error, setError] = useState("");
  const [revision, setRevision] = useState(0);
  const activeSearch = useRef<AbortController | null>(null);
  const activeExecution = useRef<AbortController | null>(null);
  const currentQuery = query ?? uncontrolledQuery;

  const setQuery = (next: string) => {
    if (query === undefined) setUncontrolledQuery(next);
    onQueryChange?.(next);
  };

  useEffect(() => {
    activeSearch.current?.abort();
    const normalized = currentQuery.trim();
    if (normalized.length < minimumQueryLength && !(normalized.length === 0 && recentCommands)) {
      setCommands([]);
      setError("");
      setState("idle");
      return;
    }
    if (normalized.length === 0 && recentCommands && adapter.loadRecent === undefined) {
      setCommands([]);
      setError("");
      setState("empty");
      return;
    }
    const controller = new AbortController();
    activeSearch.current = controller;
    setState("loading");
    setError("");
    const timer = setTimeout(() => {
      const request =
        normalized.length === 0
          ? adapter.loadRecent!(controller.signal)
          : adapter.search(normalized, controller.signal);
      void request
        .then((next) => {
          if (controller.signal.aborted) return;
          setCommands(next);
          setState(next.length === 0 ? "empty" : "ready");
        })
        .catch((searchError: unknown) => {
          if (controller.signal.aborted) return;
          setError(
            searchError instanceof Error ? searchError.message : "Search could not continue.",
          );
          setState("error");
        });
    }, debounceMs);
    return () => {
      clearTimeout(timer);
      controller.abort();
    };
  }, [adapter, currentQuery, debounceMs, minimumQueryLength, recentCommands, revision]);

  useEffect(
    () => () => {
      activeSearch.current?.abort();
      activeExecution.current?.abort();
    },
    [],
  );

  const retry = useCallback(() => setRevision((value) => value + 1), []);

  const execute = async (commandId: string) => {
    activeExecution.current?.abort();
    const controller = new AbortController();
    activeExecution.current = controller;
    try {
      await adapter.execute(commandId, controller.signal);
      setError("");
    } catch (executionError) {
      if (controller.signal.aborted) return;
      setError(
        executionError instanceof Error ? executionError.message : "The command could not run.",
      );
      setState("error");
    } finally {
      if (activeExecution.current === controller) activeExecution.current = null;
    }
  };

  return { commands, error, execute, query: currentQuery, retry, setQuery, state } as const;
}

@layer mergora.components {
  .mrg-command-center {
    display: grid;
    align-content: start;
    gap: var(--mrg-semantic-space-stack-md);
    max-inline-size: var(--mrg-semantic-container-content);
    padding: var(--mrg-semantic-density-panel-padding);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-panel);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font-family: var(--mrg-semantic-font-family-prose);
  }

  .mrg-command-center [data-slot="command-center-heading"] {
    display: flex;
    flex-wrap: wrap;
    align-items: end;
    justify-content: space-between;
    gap: var(--mrg-semantic-space-stack-md);
    padding-block-end: var(--mrg-semantic-space-inset-md);
    border-block-end: var(--mrg-semantic-border-width-emphasis) solid
      var(--mrg-semantic-color-brand-violet);
  }

  .mrg-command-center h1 {
    margin: 0;
    font-size: var(--mrg-semantic-font-size-heading-medium);
    font-weight: var(--mrg-semantic-font-weight-heading);
    line-height: var(--mrg-semantic-font-line-height-heading);
    text-wrap: balance;
  }

  .mrg-command-center [data-slot="command-center-heading"] p {
    max-inline-size: var(--mrg-semantic-size-content-prose);
    margin-block: var(--mrg-semantic-space-stack-xs) 0;
    color: var(--mrg-semantic-color-foreground-muted);
    line-height: var(--mrg-semantic-font-line-height-body);
  }

  .mrg-command-center [data-slot="command-center-heading"] kbd {
    margin-inline-start: var(--mrg-semantic-space-inline-sm);
    color: inherit;
    font-family: var(--mrg-semantic-font-family-machine);
    font-size: var(--mrg-semantic-font-size-caption);
  }

  .mrg-command-center [data-slot="command-center-result-count"] {
    padding: var(--mrg-semantic-space-inset-xs) var(--mrg-semantic-space-inset-sm);
    border-radius: var(--mrg-semantic-radius-compact);
    color: var(--mrg-semantic-color-status-info-foreground);
    background: var(--mrg-semantic-color-status-info-background);
    font-size: var(--mrg-semantic-font-size-label);
    font-weight: var(--mrg-semantic-font-weight-label);
  }

  .mrg-command-center__mobile-entry {
    display: none;
  }

  .mrg-command-center :focus-visible {
    box-shadow: 0 0 0 var(--mrg-semantic-focus-width)
      var(--mrg-semantic-color-focus-contrast-background);
    outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
    outline-offset: var(--mrg-semantic-focus-offset);
  }

  @media (max-width: 48rem) {
    .mrg-command-center {
      padding: var(--mrg-semantic-space-inset-md);
    }

    .mrg-command-center__mobile-entry {
      display: inline-flex;
    }

    .mrg-command-center [data-slot="command-center-heading"] > .mrg-button {
      display: none;
    }
  }

  @media (pointer: coarse) {
    .mrg-command-center button,
    .mrg-command-center input {
      min-block-size: var(--mrg-semantic-size-target-preferred);
    }
  }

  @media (prefers-reduced-motion: reduce) {
    .mrg-command-center * {
      scroll-behavior: auto;
      transition-duration: var(--mrg-semantic-motion-duration-reduced);
    }
  }

  @media (forced-colors: active) {
    .mrg-command-center,
    .mrg-command-center [data-slot="command-center-heading"],
    .mrg-command-center [data-slot="command-center-result-count"] {
      border-color: CanvasText;
      color: CanvasText;
      background: Canvas;
    }

    .mrg-command-center :focus-visible {
      box-shadow: none;
      outline-color: Highlight;
    }
  }
}

"use client";

import "./command-center.css";

import { useEffect, useState, type HTMLAttributes } from "react";

import { Alert } from "../../components/alert/alert";
import { Button } from "../../components/button/button";
import {
  CommandPalette,
  type CommandPaletteItem,
} from "../../components/command-palette/command-palette";
import type { CommandCenterAdapter } from "./command-center-adapter";
import { useCommandCenter } from "./command-center-state";

export interface CommandCenterProps extends Omit<
  HTMLAttributes<HTMLDivElement>,
  "onChange" | "role"
> {
  /** Consumer adapter that owns command discovery, authorization, and execution. */
  readonly adapter: CommandCenterAdapter;
  /** Adds polite result-count announcements; false removes their live output. */
  readonly announceResultCount?: boolean;
  /** Initial open state for uncontrolled modal presentation. */
  readonly defaultOpen?: boolean;
  /** Initial query for uncontrolled search. */
  readonly defaultQuery?: string;
  /** Adds the guarded Mod+K global listener; false installs no document-level shortcut. */
  readonly globalShortcut?: false | "mod-k";
  /** Non-negative character threshold below which adapter search remains idle. */
  readonly minimumQueryLength?: number;
  /** Adds a mobile-friendly entry action; false removes that action entirely. */
  readonly mobileEntryLabel?: false | string;
  /** Reports the command identifier after enabled result activation. */
  readonly onCommand?: (commandId: string) => void;
  /** Reports controlled or uncontrolled modal open-state changes. */
  readonly onOpenChange?: (open: boolean) => void;
  /** Reports controlled or uncontrolled search query changes. */
  readonly onQueryChange?: (query: string) => void;
  /** Controlled modal open state; embedded presentation is always visible. */
  readonly open?: boolean;
  /** Chooses an always-visible embedded surface or focus-managed modal presentation. */
  readonly presentation?: "embedded" | "modal";
  /** Controlled query value; use with `onQueryChange`. */
  readonly query?: string;
  /** Loads recent commands at an empty query; false removes that adapter request path. */
  readonly recentCommands?: boolean;
  /** Adds selected-command execution context; false removes the preview UI. */
  readonly showExecutionPreview?: boolean;
  /** Shows command shortcut hints; false strips them from result accessibility output. */
  readonly showShortcuts?: boolean;
}

function isEditableTarget(target: EventTarget | null): boolean {
  return (
    target instanceof HTMLElement &&
    (target.isContentEditable || /^(?:INPUT|SELECT|TEXTAREA)$/u.test(target.tagName))
  );
}

export function CommandCenter({
  "aria-label": ariaLabel = "Command center",
  adapter,
  announceResultCount = false,
  className,
  defaultOpen = false,
  defaultQuery = "",
  globalShortcut = false,
  minimumQueryLength = 1,
  mobileEntryLabel = false,
  onCommand,
  onOpenChange,
  onQueryChange,
  open,
  presentation = "embedded",
  query,
  recentCommands = false,
  showExecutionPreview = false,
  showShortcuts = false,
  ...props
}: CommandCenterProps) {
  const center = useCommandCenter({
    adapter,
    defaultQuery,
    minimumQueryLength,
    recentCommands,
    ...(onQueryChange === undefined ? {} : { onQueryChange }),
    ...(query === undefined ? {} : { query }),
  });
  const [uncontrolledOpen, setUncontrolledOpen] = useState(defaultOpen);
  const resolvedOpen = presentation === "embedded" ? true : (open ?? uncontrolledOpen);
  const setOpen = (next: boolean) => {
    if (open === undefined) setUncontrolledOpen(next);
    onOpenChange?.(next);
  };

  useEffect(() => {
    if (globalShortcut === false) return;
    const handleKeyDown = (event: KeyboardEvent) => {
      if (
        event.isComposing ||
        event.key.toLocaleLowerCase() !== "k" ||
        !(event.ctrlKey || event.metaKey) ||
        event.altKey ||
        isEditableTarget(event.target)
      ) {
        return;
      }
      event.preventDefault();
      setOpen(true);
    };
    globalThis.addEventListener("keydown", handleKeyDown);
    return () => globalThis.removeEventListener("keydown", handleKeyDown);
  }, [globalShortcut, onOpenChange, open, presentation]);

  const commands: readonly CommandPaletteItem[] = center.commands.map((command) => {
    if (showShortcuts) return command;
    const { shortcut: _shortcut, ...withoutShortcut } = command;
    return withoutShortcut;
  });
  const palette = (
    <CommandPalette
      commands={commands}
      emptyMessage={
        center.query.trim().length < minimumQueryLength
          ? `Enter at least ${minimumQueryLength} character${minimumQueryLength === 1 ? "" : "s"}.`
          : "No matching commands. Try a broader term."
      }
      label="Workspace commands"
      {...(center.state === "error" ? { loadError: center.error } : {})}
      loading={center.state === "loading"}
      onCommand={(command) => {
        void center.execute(command.id);
        onCommand?.(command.id);
        if (presentation === "modal") setOpen(false);
      }}
      onOpenChange={setOpen}
      onQueryChange={center.setQuery}
      onRetry={center.retry}
      open={resolvedOpen}
      placeholder="Search navigation and actions"
      presentation={presentation}
      query={center.query}
      shouldFilter={false}
      showExecutionPreview={showExecutionPreview}
    />
  );

  return (
    <div
      {...props}
      aria-label={ariaLabel}
      className={className === undefined ? "mrg-command-center" : `mrg-command-center ${className}`}
      data-slot="command-center"
      role="region"
    >
      <div data-slot="command-center-heading">
        <div>
          <h1>Command center</h1>
          <p>Search and run consumer-owned workspace actions from one keyboard-friendly surface.</p>
        </div>
        {presentation === "modal" ? (
          <Button onClick={() => setOpen(true)} variant="secondary">
            Open command center
            {globalShortcut === false ? null : <kbd>Ctrl/⌘ K</kbd>}
          </Button>
        ) : null}
      </div>
      {mobileEntryLabel === false ? null : (
        <Button
          className="mrg-command-center__mobile-entry"
          onClick={() => setOpen(true)}
          variant="secondary"
        >
          {mobileEntryLabel}
        </Button>
      )}
      {announceResultCount ? (
        <output aria-live="polite" data-slot="command-center-result-count">
          {center.state === "loading"
            ? "Searching commands."
            : `${commands.length} command${commands.length === 1 ? "" : "s"} available.`}
        </output>
      ) : null}
      {center.state === "error" && !resolvedOpen ? (
        <Alert
          actions={<Button onClick={center.retry}>Retry search</Button>}
          description={center.error}
          title="Command search unavailable"
          variant="error"
        />
      ) : null}
      {palette}
    </div>
  );
}

export const CommandCenterPage = CommandCenter;

export {
  createDeterministicCommandCenterAdapter,
  type CommandCenterAdapter,
  type CommandCenterItem,
} from "./command-center-adapter";
export {
  useCommandCenter,
  type CommandCenterSearchState,
  type UseCommandCenterOptions,
} from "./command-center-state";
export { CommandCenter, CommandCenterPage, type CommandCenterProps } from "./command-center";
